from flask import Flask, request, g, jsonify, abort
import time
import hashlib
from prometheus_client import (
    Counter,
    Histogram,
    generate_latest,
    CONTENT_TYPE_LATEST,
    CollectorRegistry,
)

app = Flask(__name__)

# Create a custom registry to avoid exposing default process metrics
registry = CollectorRegistry()

# Metrics should track aggregate, non-sensitive information only.
# NEVER include user IDs, API keys, request bodies, or any PII in metric labels.

# Safe metrics: track counts and latency by method, endpoint, and status code only
REQUEST_COUNT = Counter(
    "http_requests_total",
    "Total HTTP requests",
    ["method", "endpoint", "status_code"],
    registry=registry,
)

REQUEST_LATENCY = Histogram(
    "http_request_duration_seconds",
    "HTTP request latency in seconds",
    ["method", "endpoint"],
    registry=registry,
)

ERROR_COUNT = Counter(
    "http_errors_total",
    "Total HTTP errors",
    ["method", "endpoint", "status_code"],
    registry=registry,
)


# --- Authentication / Authorization helpers ---

VALID_API_KEYS = {
    "key-abc123": "user_1",
    "key-def456": "user_2",
    "key-ghi789": "admin",
}

METRICS_ALLOWED_KEYS = {"key-ghi789"}  # Only admin can view metrics


def _authenticate():
    """Authenticate the request via X-API-Key header. Returns (api_key, user_id) or aborts."""
    api_key = request.headers.get("X-API-Key")
    if not api_key or api_key not in VALID_API_KEYS:
        abort(401, description="Invalid or missing API key")
    return api_key, VALID_API_KEYS[api_key]


# --- Middleware: record metrics for every request ---

@app.before_request
def before_request_hook():
    g.start_time = time.time()


@app.after_request
def after_request_hook(response):
    latency = time.time() - getattr(g, "start_time", time.time())

    # Normalize the endpoint to the rule (e.g. /users/<id>) to avoid high-cardinality
    endpoint = request.url_rule.rule if request.url_rule else "unknown"
    method = request.method
    status = str(response.status_code)

    REQUEST_COUNT.labels(method=method, endpoint=endpoint, status_code=status).inc()
    REQUEST_LATENCY.labels(method=method, endpoint=endpoint).observe(latency)

    if response.status_code >= 400:
        ERROR_COUNT.labels(method=method, endpoint=endpoint, status_code=status).inc()

    return response


# --- /metrics endpoint: requires authentication + authorization ---

@app.route("/metrics")
def metrics():
    """
    Expose Prometheus metrics.

    This endpoint is **authenticated and authorized** — only callers with an
    admin-level API key may access it.  Exposing /metrics without authentication
    is a security anti-pattern because metrics can leak:
      • endpoint structure / internal routes
      • traffic patterns and volumes
      • error rates that aid reconnaissance
    
    We also deliberately avoid embedding any PII (user IDs, API keys, request
    bodies) in metric labels.  Prometheus labels are stored in plain text and
    are visible to anyone who can scrape the endpoint.
    """
    api_key, user_id = _authenticate()

    if api_key not in METRICS_ALLOWED_KEYS:
        abort(403, description="You are not authorized to view metrics")

    metrics_output = generate_latest(registry)
    return metrics_output, 200, {"Content-Type": CONTENT_TYPE_LATEST}


# --- Sample application endpoints ---

@app.route("/api/data", methods=["GET"])
def get_data():
    _authenticate()
    return jsonify({"data": [1, 2, 3], "status": "ok"})


@app.route("/api/data", methods=["POST"])
def post_data():
    _authenticate()
